+pub fn genCDLL(self: *NativeCodegen, args: []ast.Node) CodegenError!void {
+    try self.emit("struct {\n");
+    self.indent();
+    try self.emitIndent();
+    try self.emit("_name: []const u8 = ");
+    if (args.len > 0) {
+        try self.genExpr(args[0]);
+    } else {
+        try self.emit("\"\"");
+    }
+    try self.emit(",\n");
+    try self.emitIndent();
+    try self.emit("_handle: ?*anyopaque = null,\n");
+    self.dedent();
+    try self.emitIndent();
+    try self.emit("}{}");
+}
